

export function safeComment(val) {
  return String(val)
    .replace(/--/g, '- -')   
    .replace(/--/g, '- -')   
    .replace(/-$/, '- ');    
}

export function safeCdata(val) {
  return String(val).replace(/\]\]>/g, ']]]]><![CDATA[>')
}

export function escapeAttribute(val) {
  return String(val).replace(/"/g, '&quot;').replace(/'/g, '&apos;')
}